  def predict(triples: list[Triple]) -> str:
      """
      Convert a list of triples about airports (or related entities) into a
      single fluent sentence.  Predicates are mapped to short English phrases;
      unknown predicates fall back to a generic "predicate object" wording.
      """
      if not triples:
          return ""

      # Sort triples to prioritize airport-related subjects first
      airport_keywords = ['airport', 'lufthafen', 'aeroport', 'international', 'regional']
      def sort_key(t):
          subject_lower = t.subject.lower()
          for keyword in airport_keywords:
              if keyword in subject_lower:
                  return 0
          return 1

      sorted_triples = sorted(triples, key=sort_key)
